  ('policepromo-8b7f1efc-moex-00038', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列有關行政救濟時效之敘述，何者正確？', '["訴願之提起，應自行政處分達到或公告期滿之日起30日內為之", "人民提起訴願，如受理訴願機關於2個月內不為決定時，得逕向行政法院提起行政訴訟", "課予義務訴訟之提起，原則上應於訴願決定書送達後3個月之不變期間內為之", "依行政訴訟法提起之抗告，應於裁定送達後10日之不變期間內為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL)
